INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Zero-backend form handling$q$, $q$Point any HTML form's action attribute at a Formspark endpoint to start receiving submissions with no server code to write or host.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Spam filtering$q$, $q$Built-in honeypot and spam-detection logic filters out bot submissions before they reach an inbox.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Email notifications$q$, $q$Automatic email alerts are sent to configured recipients whenever a new submission arrives.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$File upload support$q$, $q$Forms can accept file attachments, which Formspark stores and makes available alongside the rest of the submission data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Webhooks and integrations$q$, $q$Submissions can be routed to Zapier, Slack, Google Sheets, and other third-party tools via webhooks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$AJAX and custom redirects$q$, $q$Forms can submit asynchronously without a page reload, or redirect to a custom thank-you page after submission.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Autoresponders$q$, $q$Automatic confirmation emails can be sent back to the person who filled out the form.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Non-expiring submission bundles$q$, $q$Purchased submission capacity never expires, so unused capacity carries forward indefinitely.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Submission bundles never expire, so businesses only pay for capacity they actually use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Extremely fast setup that works with any static site generator or front-end framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Unlimited team members included on every plan, including the free tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Simple, predictable pricing without a recurring subscription commitment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$No visual, drag-and-drop form builder; developers must write their own HTML$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Limited built-in analytics or reporting compared to full-featured form platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Smaller integration ecosystem than larger competitors like Formstack or Typeform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Very small company size may concern buyers evaluating long-term vendor support and reliability$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$What is Formspark used for?$q$, $q$Formspark is used to connect a plain HTML form on a static or JAMstack website to a working backend that processes submissions, filters spam, and sends email notifications without requiring custom server code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Does Formspark charge a monthly subscription?$q$, $q$No. Formspark uses a pay-as-you-go model where customers buy non-expiring submission bundles rather than paying a recurring monthly fee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Does Formspark work with React, Next.js, or other JavaScript frameworks?$q$, $q$Yes. Because Formspark is just an API endpoint that accepts a standard form POST request, it works with any front-end technology, including static HTML, React, Next.js, Vue, and Gatsby.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Does Formspark filter spam submissions?$q$, $q$Yes, Formspark includes built-in honeypot fields and spam-detection logic to reduce bot submissions without requiring a separate CAPTCHA service.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Can Formspark send data to Slack, Zapier, or Google Sheets?$q$, $q$Yes, submissions can be routed to third-party tools such as Slack, Zapier, and Google Sheets through webhooks and integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Is there a free plan for Formspark?$q$, $q$Yes, every workspace starts with 250 free submissions across up to 10 forms, with unlimited team members included.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Static site contact forms$q$, $q$Developers add a working contact form to a static marketing site or portfolio without provisioning any backend infrastructure.$q$, $q$Developers and JAMstack site builders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Lead-generation landing pages$q$, $q$Marketing agencies and small businesses collect leads from campaign landing pages and route them straight to email or a CRM via webhook.$q$, $q$Small businesses and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Waitlist and signup forms$q$, $q$Indie developers and early-stage startups capture waitlist signups for a new product launch without building custom signup infrastructure.$q$, $q$Indie hackers and early-stage startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["250 submissions included","Up to 10 forms","Unlimited team members","Spam filtering","Email notifications"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$Submission Bundle$q$, $q$$25 per 50,000 submissions (discounted from $50)$q$, $q$One-time purchase, does not expire$q$, NULL, $q$["50,000 additional submissions","Up to 100 forms","Unlimited team members","All integrations and webhooks","File uploads and autoresponders"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formspark is a form-backend-as-a-service tool that turns any plain HTML form into a working, spam-filtered submission pipeline without requiring the developer to write or host server-side code.$q$, $q$Instead of a subscription, Formspark sells non-expiring submission bundles, an unusual pricing approach in the form-backend category that suits sites with irregular or seasonal traffic.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Formspark handles spam filtering, email notifications, file uploads, custom redirects, AJAX submissions, and autoresponders, and connects to tools like Zapier, Slack, and Google Sheets through webhooks and integrations.$q$, $q$Every workspace, including the free tier, includes unlimited team members, which is a notable contrast to competitors that gate collaborator seats behind paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free plan includes 250 submissions across up to 10 forms. Additional capacity is purchased as a one-time, non-expiring bundle of 50,000 submissions for $25, raising the form limit to 100.$q$, $q$There is no recurring monthly subscription fee, so total cost scales directly with actual form volume rather than a flat seat-based price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
