INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('304e1389-15d6-4292-826c-3085c32d74e1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Drag-and-drop form builder$q$, $q$Build multi-step, conditional-logic forms visually without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Workflow automation$q$, $q$Route submitted data through approval chains and automated business processes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Document generation integration$q$, $q$Merge form data directly into contracts, invoices, and other documents via Formstack Documents.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Electronic signatures$q$, $q$Collect legally binding e-signatures on generated or uploaded documents through Formstack Sign.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$HIPAA and PCI compliant forms$q$, $q$Configure forms to meet healthcare and payment-data compliance requirements for regulated industries.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Salesforce-native integration$q$, $q$Build Salesforce-embedded forms with progressive data capture, dynamic prefill, and Salesforce Shield compatibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Online payment collection$q$, $q$Accept payments directly through forms via Stripe and PayPal integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$100+ third-party integrations$q$, $q$Connect to tools such as Google Sheets, Mailchimp, and HubSpot to sync submitted data automatically.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Broad feature set spanning forms, document generation, and e-signatures in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Strong compliance credentials, including HIPAA- and PCI-compliant form configurations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Deep native Salesforce integration for enterprise CRM-driven workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Nearly two decades of operating history and a large integration ecosystem$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$No permanent free plan, only a 14-day free trial of the core Forms product$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Entry-level pricing is higher than lightweight competitors like Google Forms or Wufoo$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Suite and Enterprise pricing can become expensive for organizations needing high usage limits$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Recent corporate rebrand to Intellistack may create short-term confusion about the product's ownership$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$What does Formstack do?$q$, $q$Formstack is a no-code platform for building online forms, generating documents from submitted data, and collecting electronic signatures, used for workflows like HR onboarding, patient intake, and event registration.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$How much does Formstack cost?$q$, $q$The Forms plan starts at $83 per month billed annually, and the Suite plan, which adds document generation and unlimited e-signatures, starts at $250 per month billed annually. Enterprise and Salesforce Solutions plans use custom pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Is Formstack HIPAA compliant?$q$, $q$Yes, Formstack offers HIPAA-compliant form configurations suitable for healthcare organizations collecting patient data, alongside PCI-compliant options for payment data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Does Formstack integrate with Salesforce?$q$, $q$Yes, Formstack offers a dedicated Salesforce Solutions package with Salesforce-native forms, document generation powered by Salesforce data, and Salesforce Shield compatibility.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Is Formstack the same company as Intellistack?$q$, $q$Yes. In June 2025, Formstack's parent company rebranded at the corporate level to Intellistack, though the Formstack product name continues to be used for its forms platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Does Formstack offer a free plan?$q$, $q$Formstack does not offer a permanent free plan, but it does offer a 14-day free trial of its core Forms product with no credit card required.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$HR onboarding and internal workflows$q$, $q$HR teams collect new-hire paperwork and route it through approval workflows without manual data entry.$q$, $q$HR and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$HIPAA-compliant patient intake$q$, $q$Healthcare organizations collect patient intake data through compliant, secure online forms.$q$, $q$Healthcare providers and clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Nonprofit donation and event registration$q$, $q$Nonprofits collect donations and manage event registrations with payment processing built into the form.$q$, $q$Nonprofits and associations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Forms$q$, $q$$83/month (annual) or $99/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["1 builder user","25 forms","1,000 submissions per form","2GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Suite$q$, $q$$250/month (annual) or $299/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["3 builder users","100 forms","5,000 submissions per form","10GB storage","Unlimited document senders","Unlimited eSignatures"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Salesforce Solutions$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Salesforce-native forms","Document generation powered by Salesforce data","Experience Cloud integration","Salesforce Shield compatibility","PCI/HIPAA-compliant solutions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Dedicated Customer Success Manager","SSO and advanced security","Custom SLAs","Unlimited users and submissions","API access and custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formstack is a no-code workplace productivity platform centered on drag-and-drop online forms, extended with document generation and electronic signature capabilities acquired over the company's nearly twenty-year history.$q$, $q$Originally founded in 2006 as FormSpring.com by Ade Olonoh, the company renamed to Formstack to avoid confusion with an unrelated social spin-off, and has since grown into a mid-market SaaS platform serving regulated industries like healthcare, government, and nonprofits.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include a visual drag-and-drop form builder, conditional logic, multi-step forms, workflow and approval automation, and payment collection via Stripe and PayPal.$q$, $q$Formstack extends beyond forms with document generation (via its Formstack Documents module) and electronic signatures (Formstack Sign), plus HIPAA- and PCI-compliant configurations and deep Salesforce integration for enterprise customers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Formstack's published plans start at $83 per month (billed annually) for the Forms plan, and $250 per month (billed annually) for the Suite plan, which bundles forms, document generation, and e-signatures.$q$, $q$Larger organizations use custom-priced Salesforce Solutions or Enterprise plans, which add dedicated support, SSO, custom SLAs, and unlimited usage; a 14-day free trial is available for the core Forms product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e0d19f35-3b93-4946-be3c-8f0848baac1e', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Template-based document merge$q$, $q$Build a reusable document template once and automatically populate it with data from forms, CRMs, or databases.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Conditional logic in documents$q$, $q$Show, hide, or change document content dynamically based on the incoming data for each merge.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Multiple output formats$q$, $q$Generate finished documents as DOCX, PPTX, PDF, or CSV files depending on the use case.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Automated routing$q$, $q$Send generated documents automatically for approval or deliver them to cloud storage services like Google Drive or Dropbox.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$CRM and database integrations$q$, $q$Pull data directly from external CRMs and databases in addition to Formstack Forms submissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$API access$q$, $q$Trigger document generation programmatically from custom applications via the Formstack Documents API.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Reusable template library$q$, $q$Store and manage multiple document templates for different document types within a single account.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$HIPAA-compliant Enterprise option$q$, $q$Custom Enterprise plans support HIPAA-compliant document generation for regulated industries.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Advanced conditional logic that adapts document content dynamically, beyond what many competitors offer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Deep native integration with Formstack Forms for an end-to-end data-to-document workflow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Automated routing to cloud storage and approval workflows reduces manual document handling$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Long operating history dating back to WebMerge's 2011 founding, with a proven high-volume merge engine$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Standalone pricing can be less economical than Formstack's bundled Suite plan for teams needing forms and e-signatures too$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Primarily focused on document generation rather than full contract lifecycle management or redlining$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Entry-level Starter plan's 150 monthly merges may be limiting for higher-volume document workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Enterprise-grade compliance features require a custom quote rather than transparent published pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$What is Formstack Documents used for?$q$, $q$Formstack Documents automates the creation of contracts, invoices, proposals, and other business documents by merging data from forms, CRMs, or databases into reusable templates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Is Formstack Documents the same as Formstack Forms?$q$, $q$No, they are separate but connected products within the Formstack platform. Formstack Forms collects data, while Formstack Documents generates finished documents from that data or other data sources.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$What was Formstack Documents called before?$q$, $q$Formstack Documents began as an independent company called WebMerge, founded in 2011, which Formstack acquired in April 2019 and rebranded into its current product.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$How much does Formstack Documents cost?$q$, $q$Standalone plans start at $110 per month for the Starter tier, rising to $220 for Teams and $440 for Pro, with custom Enterprise pricing available for larger or compliance-heavy needs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$What file formats can Formstack Documents generate?$q$, $q$Formstack Documents can generate finished documents as DOCX, PPTX, PDF, or CSV files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Can Formstack Documents integrate with a CRM?$q$, $q$Yes, it can pull data from external CRMs and databases in addition to Formstack Forms submissions, and it exposes an API for custom integrations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Automated contract and proposal generation$q$, $q$Sales and legal teams generate personalized contracts and proposals automatically from CRM data instead of manual copy-paste.$q$, $q$Sales and legal teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Insurance policy document generation$q$, $q$Insurance companies generate policy documents and compliance paperwork automatically from underwriting data.$q$, $q$Insurance and financial services firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$HR offer letters and onboarding paperwork$q$, $q$HR departments generate personalized offer letters and onboarding documents from applicant tracking data.$q$, $q$HR and people operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Starter$q$, $q$$110/month$q$, $q$Monthly or annual$q$, NULL, $q$["150 document merges per month","2 users","10 templates","Third-party integrations","Email support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Teams$q$, $q$$220/month$q$, $q$Monthly or annual$q$, NULL, $q$["Higher monthly merge allowance","More users","Additional templates","Third-party integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Pro$q$, $q$$440/month$q$, $q$Monthly or annual$q$, NULL, $q$["High-volume document merges","Expanded user and template limits","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["HIPAA-compliant document handling","High-volume document generation and processing","Dedicated support","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Formstack Documents is a no-code document-generation module that merges data from forms, CRMs, and databases into templated contracts, invoices, and reports in DOCX, PDF, PPTX, or CSV format.$q$, $q$The product originated as WebMerge, an independent document-automation company founded in 2011, which Formstack acquired in April 2019 and rebranded into its current form as part of the broader Formstack platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include a visual template builder with merge fields, conditional logic that changes document content based on incoming data, and automatic routing of finished documents to approval workflows or cloud storage like Google Drive and Dropbox.$q$, $q$Formstack Documents integrates with Formstack Forms as well as external CRMs and databases, and exposes an API for developers who want to trigger document generation from their own applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Standalone plans start at $110 per month for the Starter tier (150 merges, 2 users, 10 templates), rising to $220 per month for Teams and $440 per month for Pro, with a custom-priced Enterprise tier for larger, compliance-heavy deployments.$q$, $q$Organizations that also need forms and e-signatures often choose Formstack's bundled Suite plan at $250 per month billed annually instead of purchasing Formstack Documents as a standalone subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4cb9b0b4-da99-4023-b92a-3bceb73f3e37', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Discussion forums and Q&A$q$, $q$Members post threads, reply, and upvote or downvote content within branded discussion boards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Reputation and gamification$q$, $q$Members earn points and badges based on their contributions, encouraging ongoing participation.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Searchable knowledge base$q$, $q$Publish help articles and how-to content alongside the discussion area to help members self-serve answers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Ideation and feedback boards$q$, $q$Collect and let members vote on feature requests and product feedback in a structured format.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Flexible access controls$q$, $q$Configure communities as public, private, hidden, or restricted-access for fine-grained visibility control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Custom branding and theming$q$, $q$Style the community with built-in themes or fully custom branding, logos, and messaging.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Moderation tools$q$, $q$Control content and manage disruptive users with built-in moderation controls.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Third-party integrations$q$, $q$Connect to Slack, Zendesk, Google Analytics 360, Google Forms, Google Maps, and Zapier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$All-in-one bundle of discussion forums, knowledge base, and ideation tools in a single product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Transparent, published pricing tiers rather than requiring a sales call for every quote$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Strong customization options through branding, theming, and access controls$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Direct Zendesk integration supports support-ticket deflection workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Pricing scales up quickly once member counts exceed the Premium tier's 2,000-member limit$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Smaller integration ecosystem than larger enterprise community platforms like Khoros or Higher Logic$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Additional capacity and services (extra members, training, custom themes) require separate paid add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Reported headquarters location varies across public sources, reflecting Forumbee's smaller company profile$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$What is Forumbee used for?$q$, $q$Forumbee is used to build branded online communities for customer support deflection, product feedback collection, and employee engagement through discussion forums, Q&A, a knowledge base, and idea voting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$How much does Forumbee cost?$q$, $q$The Premium plan costs $250 per month for 5 admins and up to 2,000 members. The Enterprise plan costs $750 per month for 20 admins and up to 20,000 members, and larger deployments can move to a custom 'Build Your Own' plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Does Forumbee offer a free trial?$q$, $q$Yes, Forumbee offers a free trial without requiring credit card details.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Does Forumbee support single sign-on?$q$, $q$Yes, SAML SSO and Okta integration are available on the Enterprise plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$What integrations does Forumbee support?$q$, $q$Forumbee integrates with Google Analytics 360, Google Forms, Google Maps, Slack, Zendesk Suite, and Zapier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Can Forumbee communities be private?$q$, $q$Yes, communities can be configured as public, private, hidden, or restricted-access depending on who should be able to view and participate.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Customer support deflection$q$, $q$Companies reduce support ticket volume by letting customers find answers in a searchable knowledge base and peer discussion forum.$q$, $q$Customer support and success teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Product feedback and feature voting$q$, $q$Product teams collect and prioritize customer feature requests through an ideation and voting module.$q$, $q$Product management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Internal employee communities$q$, $q$Organizations create private, internal discussion spaces for employee engagement and knowledge sharing.$q$, $q$HR and internal communications teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Premium$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["5 admin users","Up to 2,000 members","Email support","All standard community features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Enterprise$q$, $q$$750/month$q$, $q$Monthly (dedicated success manager with annual subscription)$q$, NULL, $q$["20 admin users","Up to 20,000 members","SAML SSO and Okta integration","Optional gamification module","Dedicated success manager (annual)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$Build Your Own (Custom)$q$, $q$Custom pricing$q$, $q$Custom contract$q$, NULL, $q$["Additional admin users and members","Multiple communities","Deeper customization","Implementation services and training"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Forumbee is cloud-based community software combining discussion forums, Q&A, a knowledge base, and idea/feedback boards, aimed at businesses building branded customer or employee communities.$q$, $q$Founded in 2012, Forumbee has operated for over a decade as a smaller, privately held vendor in a community-software category that also includes open-source platforms like Discourse and Vanilla Forums.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Members can post and reply to discussion threads, upvote or downvote content, and earn reputation points and badges, while community managers publish a searchable knowledge base and manage feature-request voting through an ideation module.$q$, $q$Administrative tools include moderation controls, a member directory, real-time analytics, and integrations with Slack, Zendesk, Google Analytics, Google Forms, Google Maps, and Zapier.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Premium plan costs $250 per month for 5 admins and up to 2,000 members, while the Enterprise plan costs $750 per month for 20 admins and up to 20,000 members, with SSO and a dedicated success manager.$q$, $q$A custom 'Build Your Own' plan is available for larger deployments, alongside a menu of add-ons for extra members, extra admins, assisted setup, custom theming, and training services.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e83b9e49-d147-4636-a644-73eb25d07963', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Automated bookkeeping$q$, $q$Every transaction is automatically categorized, reducing the need for a separate accounting tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Real-time tax estimates$q$, $q$The platform calculates estimated tax liability as income arrives, helping users set aside money for quarterly taxes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Unlimited invoicing$q$, $q$Create and send unlimited invoices directly from a Found account without a separate invoicing subscription.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Contractor payments and 1099 filing$q$, $q$Pay contractors, collect W-9 forms, and file 1099-NEC forms without per-contractor fees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Pockets for fund allocation$q$, $q$Automatically set aside money into up to ten sub-accounts for taxes, savings, or other goals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Found Assistant (AI)$q$, $q$An AI-powered assistant built into the account that answers questions and completes approved tasks like moving money or sending invoices.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Team and debit cards$q$, $q$Issue debit cards for team members alongside the primary business debit card.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Tiered interest and cash back$q$, $q$Earn APY on account balances and cash back on purchases through the paid Plus and Pro tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Free core plan includes real bookkeeping, tax estimation, and unlimited invoicing with no monthly fee$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Built-in contractor payments with 1099-NEC filing removes the need for a separate payroll tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$AI-powered Found Assistant embeds account support and task automation directly into the app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Backed by well-known investors including Sequoia Capital, Founders Fund, and Lightspeed Venture Partners$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Highest interest rates and cash back are locked behind the paid Plus and Pro subscription tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Customer support leans more on email and self-service tools compared to some competitors' live support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$As a fintech rather than a chartered bank, deposits rely on third-party partner-bank relationships$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$No physical branch network, which may not suit business owners who prefer in-person banking$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Is Found a bank?$q$, $q$No, Found is a financial technology company, not a chartered bank. Banking services and FDIC insurance are provided through partner banks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$How much does Found cost?$q$, $q$Found's base account is free. Found Plus costs $35/month or $315/year, and Found Pro costs $80/month or $720/year, both with a 30-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Does Found handle tax estimates?$q$, $q$Yes, Found calculates real-time estimated tax liability as income comes in, helping self-employed users set aside money for quarterly taxes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Can Found pay contractors and file 1099s?$q$, $q$Yes, Found supports end-to-end contractor payments, including W-9 collection and 1099-NEC filing, without per-contractor fees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$What is Found Assistant?$q$, $q$Found Assistant is an AI-powered feature built into the Found account that can answer questions, help complete tasks like sending invoices or moving money, and provide account support, with money-movement actions requiring user approval.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Who founded Found?$q$, $q$Found was founded in 2019 by former Square executives Lauren Myrick (CEO) and Connor Dunn (CIO).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Freelancer and gig worker banking$q$, $q$Independent contractors manage income, expenses, and tax set-asides in one account instead of juggling separate tools.$q$, $q$Freelancers and gig workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Contractor payments for small teams$q$, $q$Small business owners pay 1099 contractors and automatically generate year-end tax forms without a separate payroll platform.$q$, $q$Solo and micro-business owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Client invoicing and cash flow tracking$q$, $q$Service-based businesses send invoices and track payment status directly within their banking account.$q$, $q$Consultants and service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Found (Free)$q$, $q$$0/month$q$, $q$No commitment$q$, NULL, $q$["Business checking account","Debit and team cards","Up to 10 Pockets","Expense tracking","Real-time tax estimates","Contractor payments","Unlimited invoicing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Found Plus$q$, $q$$35/month or $315/year$q$, $q$Monthly or annual (25% savings annually)$q$, NULL, $q$["1.50% APY on balances up to $20,000","Transaction imports","Unlimited auto-categorization rules","Custom tags and categories","Priority phone support","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$Found Pro$q$, $q$$80/month or $720/year$q$, $q$Monthly or annual (25% savings annually)$q$, NULL, $q$["2.50% APY on all balances, no cap","1% cash back on purchases","Dedicated account manager","Premium metal debit card","Free check sending","Discounted wire transfers","30-day free trial"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Found is a fintech platform offering business banking purpose-built for the self-employed, combining a checking account with automated bookkeeping, real-time tax estimates, invoicing, and contractor payments in one product.$q$, $q$Founded in 2019 by former Square executives Lauren Myrick and Connor Dunn, Found publicly launched with a $12.75 million Sequoia-led seed round in 2021 and has since raised roughly $124 million in total funding.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every transaction is automatically categorized for bookkeeping, and the platform calculates real-time estimated tax liability so users know how much to set aside for quarterly taxes as money comes in.$q$, $q$Found supports unlimited invoicing, end-to-end contractor payments with W-9 collection and 1099-NEC filing, up to ten Pockets for allocating funds toward specific goals, and an AI-powered Found Assistant for account tasks and support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The base Found account is free and includes core checking, debit cards, Pockets, expense tracking, tax estimates, and unlimited invoicing.$q$, $q$Found Plus costs $35/month ($315/year) and adds 1.50% APY up to $20,000 and transaction imports, while Found Pro costs $80/month ($720/year) and adds 2.50% APY with no cap, 1% cash back, and a dedicated account manager.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('22c9265b-8d90-4eb5-973c-a18df96a2516', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
