INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Revenue-based financing$q$, $q$Receive upfront capital sized against ARR, repaid as fixed monthly installments at a flat discount fee.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Term loans$q$, $q$Access traditional term loan financing starting at 14% APR as an alternative to revenue financing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Line of credit$q$, $q$Draw variable-rate credit as needed, with pricing that varies by the amount drawn.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Stripe-integrated underwriting$q$, $q$Connect existing payments and subscription data via Stripe to speed up financing decisions with verified revenue metrics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Low revenue qualification bar$q$, $q$Qualify with as little as $10,000 in monthly recurring revenue, lower than many competing revenue-financing providers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$No warrants or prepayment penalties$q$, $q$Financing products carry no equity warrants, no prepayment penalties, and no origination or closing fees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$SaaS financing education resources$q$, $q$Access guides and comparisons covering revenue-based financing, term loans, and other SaaS funding options.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Fast, data-driven decisions$q$, $q$Underwriting relies on real recurring-revenue data rather than lengthy manual financial-statement review.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Non-dilutive capital lets SaaS founders raise growth funding without giving up equity or a board seat$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Low $10,000 MRR qualification bar makes it accessible to earlier-stage SaaS companies than competitors like Capchase$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Transparent flat-fee pricing with no warrants, origination fees, or prepayment penalties$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Stripe-integrated underwriting speeds up the financing decision process using verified revenue data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Exclusively serves B2B SaaS companies, so it is not an option for non-recurring-revenue businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Revenue financing still carries a real cost (from a 7% flat discount fee) compared to free cash reserves$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$An optional $250/month platform fee adds cost for founders who want the broader software features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Lean team size relative to capital deployed may mean less hands-on support than larger lenders$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$What is Founderpath?$q$, $q$Founderpath is a non-dilutive financing platform that provides revenue-based financing, term loans, and lines of credit to B2B SaaS companies, sized against their existing monthly recurring revenue.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$How much does Founderpath financing cost?$q$, $q$Revenue Financing starts at a 7% flat discount fee with no origination or closing costs. Term Loans start at 14% APR, and Line of Credit pricing varies by draw amount.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$What is the minimum revenue required to qualify for Founderpath?$q$, $q$Founderpath requires a minimum of $10,000 in monthly recurring revenue, roughly $120,000 in annual recurring revenue, one of the lowest entry bars in the revenue-based financing market.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Does Founderpath take equity in exchange for financing?$q$, $q$No, Founderpath's financing products are non-dilutive, meaning founders do not give up equity, warrants, or a board seat in exchange for capital.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Who founded Founderpath?$q$, $q$Founderpath was founded in 2019 by Nathan Latka and is headquartered in Austin, Texas.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$How is Founderpath different from Capchase or Lighter Capital?$q$, $q$Founderpath has a lower minimum revenue requirement ($10,000 MRR) compared to Capchase (around $1 million ARR) and Lighter Capital (around $500,000 ARR), making it accessible to earlier-stage SaaS companies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Non-dilutive growth capital for customer acquisition$q$, $q$SaaS founders raise upfront capital against ARR to fund marketing and sales hiring without diluting ownership.$q$, $q$Bootstrapped and early-stage B2B SaaS founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Bridging cash flow between funding rounds$q$, $q$Growth-stage SaaS companies use revenue financing or a line of credit to smooth cash flow between equity rounds.$q$, $q$Venture-backed SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Funding an acquisition or buyout$q$, $q$SaaS founders use term loans or revenue financing to fund the acquisition of a competing product or company.$q$, $q$SaaS founders pursuing M&A$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Revenue Financing$q$, $q$From a 7% flat discount fee$q$, $q$Fixed monthly installments over the repayment term$q$, NULL, $q$["Up to roughly 50% of ARR upfront","No origination fees","No warrants","No prepayment penalties","Minimum $10K MRR to qualify"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Term Loan$q$, $q$From 14% APR$q$, $q$Fixed monthly repayment$q$, NULL, $q$["Traditional loan structure","No setup or closing costs","Sized against recurring revenue"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Line of Credit$q$, $q$Varies by draw amount$q$, $q$Revolving credit$q$, NULL, $q$["Flexible access to capital as needed","Pricing scales with amount drawn"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$Platform Software Fee (optional)$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["Access to additional platform and software features","Separate from financing product costs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Founderpath is a non-dilutive financing platform exclusively for B2B SaaS founders, offering revenue-based financing, term loans, and lines of credit sized against existing monthly recurring revenue rather than equity.$q$, $q$Founded in 2019 by Nathan Latka and headquartered in Austin, Texas, the company has kept a lean team of roughly ten employees while reporting profitability since 2021.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The flagship Revenue Financing product provides upfront capital of up to roughly 50% of ARR at a flat 7% discount fee, repaid in fixed monthly installments with no origination fees, warrants, or prepayment penalties.$q$, $q$Founderpath integrates directly with Stripe and other financial systems to underwrite deals using verified recurring-revenue data, and offers term loans starting at 14% APR and a variable-rate line of credit as alternative capital products.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Revenue Financing starts at a 7% flat discount fee with no setup, origination, or closing costs, while Term Loans start at 14% APR and Line of Credit pricing varies by draw amount.$q$, $q$A minimum of $10,000 MRR (about $120,000 ARR) is required to qualify, one of the lowest entry bars among revenue-based financing providers; an optional $250/month platform fee applies to separate software features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('806674db-f3e6-419b-a6a4-aa3e4199d96e', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Text and image editing$q$, $q$Directly edit text and images within a PDF document without needing to recreate the file from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$OCR for scanned documents$q$, $q$Convert scanned paper documents into editable, searchable text using optical character recognition.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$PDF conversion$q$, $q$Convert PDFs to and from other formats such as Word, Excel, and PowerPoint.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$AI Smart Redact$q$, $q$Automatically identify and remove sensitive information such as Social Security numbers and credit card details from documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$AI Assistant$q$, $q$Summarize, analyze, and chat with document content using built-in AI credits included in every subscription.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Digital signatures and encryption$q$, $q$Apply digital signatures and password protection to secure sensitive documents (PDF Editor+ tier).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Mobile apps$q$, $q$Edit and review PDFs on iOS and Android devices with PDF Editor+.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Customizable fillable forms$q$, $q$Create interactive, fillable PDF forms for data collection or contracts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Significantly more affordable than Adobe Acrobat while covering most core PDF editing needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$AI Smart Redact automates sensitive-data removal that would otherwise require manual review$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Includes a genuinely free standalone PDF reader alongside the paid editing subscriptions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Volume discounts of up to 30% make it cost-effective for larger teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Mobile apps and several premium features are gated behind the higher-priced PDF Editor+ tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Foxit eSign Business requires a 5-seat minimum purchase, adding cost for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$AI Assistant's free tier is limited to 20 credits per month before requiring a paid add-on$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Company's origin and dual US/China corporate structure has drawn scrutiny in some government and enterprise security discussions$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$How much does Foxit PDF Editor cost?$q$, $q$Foxit PDF Editor costs $10.99/month or $129.99/year per user, while the higher PDF Editor+ tier costs $13.99/month or $159.99/year per user.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$What is the difference between PDF Editor and PDF Editor+?$q$, $q$PDF Editor+ adds mobile apps for iOS and Android, digital signatures, password protection and encryption, customizable fillable forms, and the AI-powered Smart Redact feature on top of the base PDF Editor plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Does Foxit PDF Editor include AI features?$q$, $q$Yes, every subscription includes Foxit's AI Assistant with 20 free credits per month for tasks like document summarization, with a $49.99/year add-on unlocking 2,000 credits per billing cycle.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Is there a free version of Foxit's PDF software?$q$, $q$Yes, Foxit offers Foxit PDF Reader as a completely free, standalone product separate from the paid PDF Editor subscriptions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Does Foxit offer electronic signatures?$q$, $q$Yes, through the separate Foxit eSign product, priced at $120/year for Essentials (250 envelopes) or $300/user/year with a 5-seat minimum for Business (unlimited envelopes).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Who founded Foxit Software?$q$, $q$Foxit Software was founded in 2001 by Eugene Y. Xiong, and released its first product, Foxit Reader, in 2004.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Affordable PDF editing for students and freelancers$q$, $q$Individuals get core PDF editing, conversion, and OCR capabilities without paying for a full Adobe Acrobat subscription.$q$, $q$Students and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Compliance-driven document redaction$q$, $q$Legal and HR teams use AI Smart Redact to quickly remove sensitive personal information before sharing documents externally.$q$, $q$Legal, HR, and compliance teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$Enterprise document workflows with e-signature$q$, $q$Larger teams standardize on Foxit PDF Editor and Foxit eSign Business for regulated document creation, editing, and signing at volume-discounted pricing.$q$, $q$Enterprise office and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$PDF Editor$q$, $q$$10.99/month or $129.99/year per user$q$, $q$Monthly or annual$q$, NULL, $q$["Desktop editing (Windows/macOS) and web app","20GB cloud storage","Text and image editing","PDF conversion and OCR","Merge, rearrange, delete, rotate pages","20 free AI Assistant credits per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$PDF Editor+$q$, $q$$13.99/month or $159.99/year per user$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in PDF Editor","Mobile apps (iOS and Android)","AI Smart Redact","Digital signatures","Password protection and encryption","Customizable fillable forms","Annotations and comments","14-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$AI Assistant Add-on$q$, $q$$49.99/year$q$, $q$Annual$q$, NULL, $q$["2,000 AI credits per billing cycle","Document summarization and analysis","Chat with document content"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$eSign Essentials$q$, $q$$120/year per user$q$, $q$Annual$q$, NULL, $q$["250 envelopes per year","Legally binding signatures","Reusable templates","Document tracking","No minimum seat requirement"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$eSign Business$q$, $q$$300/user/year (5-seat minimum)$q$, $q$Annual$q$, NULL, $q$["Unlimited envelopes and templates","No overage fees","HIPAA and 21 CFR Part 11 support","SOC 2 Type II, eIDAS, QES, GDPR compliance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Foxit PDF Editor is a cross-platform PDF editing suite from Foxit Software, positioned as a more affordable alternative to Adobe Acrobat, offering text and image editing, OCR, conversion, and AI-powered document tools.$q$, $q$Founded in 2001 by Eugene Y. Xiong, Foxit built its early reputation with the free Foxit Reader in 2004, later incorporating as Foxit Corporation in 2009 and going public on China's NEEQ market in 2015.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The base PDF Editor tier covers desktop and web editing, OCR, file merging, and format conversion, while the higher PDF Editor+ tier adds mobile apps, digital signatures, password protection, fillable forms, and an AI-powered Smart Redact tool for automatically removing sensitive information.$q$, $q$Both tiers include Foxit's AI Assistant with monthly free credits for document summarization and Q&A, with an optional add-on unlocking a much larger monthly credit allowance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PDF Editor costs $10.99/month or $129.99/year per user, and PDF Editor+ costs $13.99/month or $159.99/year per user, with a 14-day free trial and volume discounts up to 30% for larger teams.$q$, $q$A companion e-signature product, Foxit eSign, is priced separately at $120/year (Essentials, 250 envelopes) or $300/user/year with a 5-seat minimum (Business, unlimited envelopes).$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('92d699c1-88c8-4560-8348-409710af3ec5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
