INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Real-code visual editor$q$, $q$Design in a visual canvas that renders actual production website code rather than a static mockup requiring developer handoff.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Built-in CMS$q$, $q$Manage structured content like blog posts or portfolio items through a native content management system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$AI-assisted site generation$q$, $q$Describe a website and have Framer generate an initial design and layout to edit from.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Animations and interactions$q$, $q$Build rich, interactive animations carried over from Framer's design-prototyping heritage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Staging environment with branching$q$, $q$Work on site changes in a staging environment with previews before publishing live, available on Pro and above.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Built-in SEO tools$q$, $q$Configure meta tags, redirects, and other SEO settings directly within the site builder.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Localization support$q$, $q$Publish multi-language versions of a site using translation locale add-ons.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Integrated hosting$q$, $q$Every paid plan includes hosting, removing the need for a separate hosting provider.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Exceptional visual design freedom and interaction design tools compared to most no-code website builders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Generous free plan supports up to 1,000 pages and a full CMS for evaluation before paying$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Renders real production code, resulting in fast-loading published sites rather than a heavier abstraction layer$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Rapid recent investment in AI-assisted site generation speeds up the design process$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Smaller third-party plugin, integration, and template ecosystem than WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$E-commerce features are less mature than dedicated platforms or longer-established competitors like Webflow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Add-on costs for extra editors, advanced hosting, and A/B testing can increase total cost for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Enterprise pricing is fully custom, requiring a sales conversation rather than transparent published pricing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$What is Framer used for?$q$, $q$Framer is used to visually design, build, and host production websites without writing code, including marketing sites, portfolios, and startup landing pages.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$How much does Framer cost?$q$, $q$Framer has a free plan, a Basic plan at $10/month, a Pro plan at $30/month, and a custom-priced Enterprise plan, with add-ons available for extra editors, translation locales, A/B testing, and advanced hosting.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Who founded Framer and when?$q$, $q$Framer was founded in Amsterdam in 2014 by Koen Bok and Jorn van Dijk. It began as a design and prototyping tool before pivoting to a full no-code website builder around 2020-2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Is Framer the same as Figma?$q$, $q$No. Framer originated as a separate interactive prototyping tool and has since pivoted into a no-code website builder, making it more comparable to Webflow than to Figma today.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Does Framer include hosting?$q$, $q$Yes, hosting is included in every paid Framer plan, and an advanced hosting configuration is available as a paid add-on for teams with additional technical requirements.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$What is Framer's current valuation and funding?$q$, $q$Framer raised a $100 million Series D round in August 2025 at a $2 billion valuation, led by existing investors Meritech and Atomico, bringing its total funding to roughly $160-188 million.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Startup and company websites$q$, $q$Startups design and publish their primary marketing website without hiring a developer, a workflow used by a large share of a recent Y Combinator batch.$q$, $q$Startup founders and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Designer portfolios$q$, $q$Individual designers build visually rich, interactive portfolio sites that showcase design work directly in the browser.$q$, $q$Freelance and independent designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Agency client website delivery$q$, $q$Design agencies build and hand off client websites using Framer's CMS and staging environment for structured collaboration.$q$, $q$Design and marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["500 credits","Free Framer subdomain","1GB bandwidth","Up to 10 CMS collections","Up to 1,000 pages","5MB file uploads"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Basic$q$, $q$$10/month$q$, $q$Monthly or annual$q$, NULL, $q$["Free custom domain","2 CMS collections","50GB bandwidth","Built-in SEO","Up to 30 site pages","Optional localization add-on"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Pro$q$, $q$$30/month$q$, $q$Monthly or annual$q$, NULL, $q$["Free custom domain","10 CMS collections","100GB bandwidth","Site redirects","Staging environment","Branching with previews","Up to 150 pages","Up to 2,500 CMS items"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Custom usage limits","Unlimited editors","Enterprise-grade security","Uptime guarantee","SCIM provisioning","SSO"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Framer is a no-code website builder that evolved from a high-end interactive design and prototyping tool into a platform for designing, building, and hosting production websites without writing code.$q$, $q$Founded in Amsterdam in 2014 by Koen Bok and Jorn van Dijk, Framer pivoted from a design-prototyping tool to a full website builder around 2020-2021, reaching a $2 billion valuation after an August 2025 Series D round.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Framer renders real production code as designers build, offering pixel-accurate previews, a built-in CMS, animation and interaction tools, responsive breakpoints, built-in SEO, and localization support for multi-language sites.$q$, $q$Higher tiers add a staging environment with branching and previews, AI-assisted site generation, and integrated hosting on every paid plan, with add-ons for A/B testing (Convert) and advanced hosting configurations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan supports up to 1,000 pages with a Framer subdomain, while Basic ($10/month) adds a custom domain and Pro ($30/month) adds a staging environment, branching, and up to 150 pages.$q$, $q$Enterprise uses custom pricing with unlimited editors, SSO, and SCIM, and add-ons include extra editor seats, translation locales, A/B testing, and advanced hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0eb2413c-7ff7-4575-ac2b-3bd288d5a1e3', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
